function log(message, color = 'reset') {
  const timestamp = new Date().toISOString();
  console.log(`${COLORS[color]}[${timestamp}] ${message}${COLORS.reset}`);
}

function logStep(stepName) {
  log(`\n${'='.repeat(60)}`, 'cyan');
  log(`  STEP: ${stepName}`, 'cyan');
  log(`${'='.repeat(60)}`, 'cyan');
}

function logSuccess(message) {
  log(`✅ ${message}`, 'green');
}

function logError(message) {
  log(`❌ ${message}`, 'red');
}

function logWarning(message) {
  log(`⚠️  ${message}`, 'yellow');
  pipelineState.warnings.push(message);
}

function logInfo(message) {
  log(`ℹ️  ${message}`, 'blue');
}

function exec(command, options = {}) {
  const defaultOptions = {
    cwd: CONFIG.projectRoot,
    stdio: 'pipe',
    encoding: 'utf-8',
    env: { ...process.env, NODE_ENV: CONFIG.nodeEnv },
    timeout: 300000, // 5 minute default timeout
  };

  const mergedOptions = { ...defaultOptions, ...options };

  logInfo(`Executing: ${command}`);

  try {
    const result = execSync(command, mergedOptions);
    return { success: true, output: result ? result.toString().trim() : '' };
  } catch (error) {
    return {
      success: false,
      output: error.stdout ? error.stdout.toString().trim() : '',
      error: error.stderr ? error.stderr.toString().trim() : error.message,
      exitCode: error.status,
    };
  }
}

function execWithRetry(command, options = {}, retries = CONFIG.maxRetries) {
  for (let attempt = 1; attempt <= retries; attempt++) {
    const result = exec(command, options);
    if (result.success) return result;

    if (attempt < retries) {
      logWarning(`Attempt ${attempt}/${retries} failed for: ${command}. Retrying in ${attempt * 2}s...`);
      execSync(`sleep ${attempt * 2}`);
    } else {
      return result;
    }
  }
}

function fileExists(filePath) {
  return fs.existsSync(path.join(CONFIG.projectRoot, filePath));
}

function readJson(filePath) {
  try {
    const fullPath = path.join(CONFIG.projectRoot, filePath);
    return JSON.parse(fs.readFileSync(fullPath, 'utf-8'));
  } catch {
    return null;
  }
}

function writeJson(filePath, data) {
  const fullPath = path.join(CONFIG.projectRoot, filePath);
  fs.writeFileSync(fullPath, JSON.stringify(data, null, 2));
}

function ensureDir(dirPath) {
  const fullPath = path.isAbsolute(dirPath) ? dirPath : path.join(CONFIG.projectRoot, dirPath);
  if (!fs.existsSync(fullPath)) {
    fs.mkdirSync(fullPath, { recursive: true });
  }
}

function getElapsedTime(startTime) {
  const elapsed = Date.now() - startTime;
  const seconds = Math.floor(elapsed / 1000);
  const minutes = Math.floor(seconds / 60);
  const remainingSeconds = seconds % 60;
  return minutes > 0 ? `${minutes}m ${remainingSeconds}s` : `${seconds}s`;
}

async function runStep(name, fn) {
  logStep(name);
  const stepStart = Date.now();
  const step = { name, startTime: stepStart, status: 'running' };
  pipelineState.steps.push(step);

  try {
    await fn();
    step.status = 'success';
    step.duration = getElapsedTime(stepStart);
    logSuccess(`${name} completed in ${step.duration}`);
    return true;
  } catch (error) {
    step.status = 'failed';
    step.duration = getElapsedTime(stepStart);
    step.error = error.message;
    pipelineState.errors.push({ step: name, error: error.message });
    logError(`${name} failed after ${step.duration}: ${error.message}`);
    return false;
  }
}

