function gatherInfo() {
  // Get git information
  const commitResult = exec('git rev-parse --short HEAD');
  pipelineState.commitHash = commitResult.success ? commitResult.output : 'unknown';

  const branchResult = exec('git rev-parse --abbrev-ref HEAD');
  pipelineState.branch = branchResult.success ? branchResult.output : 'unknown';

  // Get package version
  const pkg = readJson('package.json');
  if (pkg) {
    pipelineState.version = pkg.version || '0.0.0';
  }

  logInfo(`Commit: ${pipelineState.commitHash}`);
  logInfo(`Branch: ${pipelineState.branch}`);
  logInfo(`Version: ${pipelineState.version}`);
  logInfo(`Deploy Target: ${CONFIG.deployTarget}`);
  logInfo(`Node.js: ${process.version}`);
  logInfo(`Platform: ${os.platform()} ${os.arch()}`);
  logInfo(`CPUs: ${os.cpus().length}`);
  logInfo(`Free Memory: ${Math.round(os.freemem() / 1024 / 1024)}MB`);

  if (CONFIG.dryRun) {
    logWarning('DRY RUN MODE - No actual deployment will occur');
  }
}

function validateEnvironment() {
  // Check Node.js version
  const nodeVersion = process.version;
  const majorVersion = parseInt(nodeVersion.slice(1).split('.')[0]);
  if (majorVersion < 16) {
    throw new Error(`Node.js >= 16 required, found ${nodeVersion}`);
  }

  // Check required files
  if (!fileExists('package.json')) {
    throw new Error('package.json not found in project root');
  }

  // Check required environment variables for deployment
  if (!CONFIG.skipDeploy && CONFIG.deployTarget === 'production') {
    const requiredEnvVars = ['DEPLOY_HOST'];
    const missing = requiredEnvVars.filter(v => !process.env[v]);
    if (missing.length > 0 && !CONFIG.dryRun) {
      logWarning(`Missing environment variables for deployment: ${missing.join(', ')}`);
    }
  }

  // Check for lock file
  const hasNpmLock = fileExists('package-lock.json');
  const hasYarnLock = fileExists('yarn.lock');
  const hasPnpmLock = fileExists('pnpm-lock.yaml');

  if (!hasNpmLock && !hasYarnLock && !hasPnpmLock) {
    logWarning('No lock file found. Consider committing a lock file for reproducible builds.');
  }

  // Detect package manager
  if (hasPnpmLock) {
    CONFIG.packageManager = 'pnpm';
  } else if (hasYarnLock) {
    CONFIG.packageManager = 'yarn';
  } else {
    CONFIG.packageManager = 'npm';
  }

  logInfo(`Package Manager: ${CONFIG.packageManager}`);
}

function cleanPreviousBuild() {
  const dirsToClean = [CONFIG.buildDir, CONFIG.artifactDir, '.cache', 'coverage'];

  for (const dir of dirsToClean) {
    if (fileExists(dir)) {
      logInfo(`Cleaning ${dir}/`);
      exec(`rm -rf ${dir}`);
    }
  }
}

function installDependencies() {
  const pm = CONFIG.packageManager;

  // Use frozen lockfile for CI reproducibility and speed
  let installCmd;
  switch (pm) {
    case 'pnpm':
      installCmd = 'pnpm install --frozen-lockfile --prefer-offline';
      break;
    case 'yarn':
      installCmd = 'yarn install --frozen-lockfile --prefer-offline --network-timeout 60000';
      break;
    default:
      installCmd = 'npm ci --prefer-offline --no-audit --no-fund';
  }

  // Set up npm cache directory for speed
  ensureDir(CONFIG.cacheDir);

  const result = execWithRetry(installCmd, {
    env: {
      ...process.env,
      npm_config_cache: path.join(CONFIG.cacheDir, 'npm'),
      YARN_CACHE_FOLDER: path.join(CONFIG.cacheDir, 'yarn'),
    },
  });

  if (!result.success) {
    throw new Error(`Dependency installation failed: ${result.error}`);
  }

  // Verify node_modules
  if (!fileExists('node_modules')) {
    throw new Error('node_modules directory not found after installation');
  }

  logSuccess('Dependencies installed successfully');
}

function securityAudit() {
  logInfo('Running security audit...');

  const pm = CONFIG.packageManager;
  let auditCmd;

  switch (pm) {
    case 'pnpm':
      auditCmd = 'pnpm audit --prod';
      break;
    case 'yarn':
      auditCmd = 'yarn audit --groups dependencies';
      break;
    default:
      auditCmd = 'npm audit --production --audit-level=high';
  }

  const result = exec(auditCmd);

  if (!result.success) {
    // Audit failures are warnings, not blockers (configurable)
    logWarning('Security audit found vulnerabilities. Review the output above.');
    if (result.output) logInfo(result.output);
  } else {
    logSuccess('Security audit passed');
  }
}

function runLinting() {
  if (CONFIG.skipLint) {
    logWarning('Linting skipped (SKIP_LINT=true)');
    return;
  }

  const pkg = readJson('package.json');
  const scripts = pkg?.scripts || {};

  // Try lint script
  if (scripts.lint) {
    const result = exec(`${CONFIG.packageManager} run lint`);
    if (!result.success) {
      throw new Error(`Linting failed: ${result.error || result.output}`);
    }
    logSuccess('Linting passed');
  } else if (fileExists('.eslintrc.js') || fileExists('.eslintrc.json') || fileExists('.eslintrc') || fileExists('.eslintrc.yml')) {
    const result = exec('npx eslint . --ext .js,.jsx,.ts,.tsx --max-warnings 0');
    if (!result.success) {
      throw new Error(`ESLint failed: ${result.error || result.output}`);
    }
    logSuccess('ESLint passed');
  } else {
    logWarning('No linting configuration found, skipping');
  }

  // Type checking if TypeScript
  if (fileExists('tsconfig.json') && (scripts['type-check'] || scripts.typecheck)) {
    const typeCheckScript = scripts['type-check'] ? 'type-check' : 'typecheck';
    const result = exec(`${CONFIG.packageManager} run ${typeCheckScript}`);
    if (!result.success) {
      throw new Error(`Type checking failed: ${result.error || result.output}`);
    }
    logSuccess('Type checking passed');
  } else if (fileExists('tsconfig.json')) {
    const result = exec('npx tsc --noEmit');
    if (!result.success) {
      throw new Error(`TypeScript compilation check failed: ${result.error || result.output}`);
    }
    logSuccess('TypeScript compilation check passed');
  }
}

function runTests() {
  if (CONFIG.skipTests) {
    logWarning('Tests skipped (SKIP_TESTS=true)');
    return;
  }

  const pkg = readJson('package.json');
  const scripts = pkg?.scripts || {};

  if (!scripts.test && !scripts['test:ci']) {
    logWarning('No test script found in package.json, skipping tests');
    return;
  }

  const testScript = scripts['test:ci'] ? 'test:ci' : 'test';

  // Build test command with CI optimizations
  let testCmd = `${CONFIG.packageManager} run ${testScript}`;

  // Add CI-specific flags if using common test runners
  const testEnv = {
    ...process.env,
    CI: 'true',
    NODE_ENV: 'test',
    FORCE_COLOR: '1',
  };

  if (CONFIG.parallelTests) {
    testEnv.JEST_MAX_WORKERS = Math.max(1, Math.floor(os.cpus().length / 2)).toString();
  }

  const result = exec(testCmd, {
    env: testEnv,
    timeout: CONFIG.testTimeout,
  });

  if (!result.success) {
    if (result.output) {
      console.log(result.output);
    }
    throw new Error(`Tests failed: ${result.error || 'See output above'}`);
  }

  if (result.output) {
    // Extract and display test summary
    const lines = result.output.split('\n');
    const summaryLines = lines.filter(l =>
      l.includes('Tests:') || l.includes('Suites:') ||
      l.includes('passing') || l.includes('failing') ||
      l.includes('test suites') || l.includes('tests passed')
    );
    if (summaryLines.length > 0) {
      logInfo('Test Summary:');
      summaryLines.forEach(l => logInfo(`  ${l.trim()}`));
    }
  }

  logSuccess('All tests passed');
}

function buildApplication() {
  const pkg = readJson('package.json');
  const scripts = pkg?.scripts || {};

  if (!scripts.build) {
    logWarning('No build script found in package.json');

    // Check if the application is a simple Node.js app that doesn't need building
    if (fileExists('index.js') || fileExists('server.js') || fileExists('app.js')) {
      logInfo('Detected a server application that may not require a build step');
      return;
    }

    throw new Error('No build script and no entry point found');
  }

  const buildEnv = {
    ...process.env,
    NODE_ENV: 'production',
    CI: 'true',
    // Performance optimizations
    GENERATE_SOURCEMAP: process.env.GENERATE_SOURCEMAP || 'true',
  };

  const result = exec(`${CONFIG.packageManager} run build`, {
    env: buildEnv,
    timeout: 600000, // 10 minute timeout for builds
  });

  if (!result.success) {
    throw new Error(`Build failed: ${result.error || result.output}`);
  }

  // Verify build output
  if (scripts.build && !fileExists(CONFIG.buildDir)) {
    // Check common alternative build directories
    const altDirs = ['build', 'out', 'output', '.next', '.nuxt', 'public'];
    const found = altDirs.find(d => fileExists(d));
    if (found) {
      logInfo(`Build output found in ${found}/ (not ${CONFIG.buildDir}/)`);
      CONFIG.buildDir = found;
    } else {
      logWarning(`Build directory ${CONFIG.buildDir}/ not found. Build may output elsewhere.`);
    }
  }

  // Report build size
  if (fileExists(CONFIG.buildDir)) {
    const sizeResult = exec(`du -sh ${CONFIG.buildDir}`);
    if (sizeResult.success) {
      logInfo(`Build size: ${sizeResult.output.split('\t')[0]}`);
    }
  }

  logSuccess('Application built successfully');
}

function createArtifacts() {
  ensureDir(CONFIG.artifactDir);

  const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
  const artifactName = `deploy-${pipelineState.version}-${pipelineState.commitHash}-${timestamp}`;

  // Create deployment package
  const filesToInclude = [];

  // Include build output
  if (fileExists(CONFIG.buildDir)) {
    filesToInclude.push(CONFIG.buildDir);
  }

  // Include server files if they exist
  const serverFiles = ['server.js', 'index.js', 'app.js', 'server/', 'src/'];
  serverFiles.forEach(f => {
    if (fileExists(f)) filesToInclude.push(f);
  });

  // Include essential config files
  const configFiles = [
    'package.json',
    'package-lock.json',
    'yarn.lock',
    'pnpm-lock.yaml',
    '.env.production',
    'ecosystem.config.js',
    'pm2.config.js',
    'Dockerfile',
    'docker-compose.yml',
    'docker-compose.production.yml',
    'nginx.conf',
  ];

  configFiles.forEach(f => {
    if (fileExists(f)) filesToInclude.push(f);
  });

  if (filesToInclude.length === 0) {
    logWarning('No files found to package for deployment');
    return;
  }

  const tarFile = path.join(CONFIG.artifactDir, `${artifactName}.tar.gz`);
  const result = exec(`tar -czf ${tarFile} ${filesToInclude.join(' ')}`);

  if (!result.success) {
    throw new Error(`Failed to create artifact: ${result.error}`);
  }

  // Store artifact info
  const artifactInfo = {
    name: artifactName,
    file: tarFile,
    version: pipelineState.version,
    commit: pipelineState.commitHash,
    branch: pipelineState.branch,
    timestamp: new Date().toISOString(),
    files: filesToInclude,
  };

  writeJson(path.join(CONFIG.artifactDir, 'artifact-info.json'), artifactInfo);

  const sizeResult = exec(`du -sh ${tarFile}`);
  if (sizeResult.success) {
    logInfo(`Artifact size: ${sizeResult.output.split('\t')[0]}`);
  }

  CONFIG.artifactFile = tarFile;
  CONFIG.artifactName = artifactName;

  logSuccess(`Artifact created: ${artifactName}`);
}

function deploy() {
  if (CONFIG.skipDeploy) {
    logWarning('Deployment skipped (SKIP_DEPLOY=true)');
    return;
  }

  if (CONFIG.dryRun) {
    logWarning('DRY RUN: Deployment would be executed here');
    logInfo(`Would deploy to: ${CONFIG.deployUser}@${CONFIG.deployHost}:${CONFIG.deployPath}`);
    return;
  }

  // Detect deployment strategy
  if (fileExists('Dockerfile') || fileExists('docker-compose.yml')) {
    deployDocker();
  } else if (fileExists('ecosystem.config.js') || fileExists('pm2.config.js')) {
    deployPM2();
  } else {
    deploySCP();
  }
}

function deployDocker() {
  logInfo('Deploying with Docker...');

  const tag = `${pipelineState.version}-${pipelineState.commitHash}`;
  const imageName = process.env.DOCKER_IMAGE || `app:${tag}`;

  // Build Docker image
  let buildCmd = `docker build -t ${imageName} .`;

  // Use BuildKit for faster builds
  const buildResult = exec(buildCmd, {
    env: { ...process.env, DOCKER_BUILDKIT: '1' },
    timeout: 600000,
  });

  if (!buildResult.success) {
    throw new Error(`Docker build failed: ${buildResult.error}`);
  }

  // If we have a registry, push the image
  const registry = process.env.DOCKER_REGISTRY;
  if (registry) {
    const fullImageName = `${registry}/${imageName}`;

    exec(`docker tag ${imageName} ${fullImageName}`);

    const pushResult = execWithRetry(`docker push ${fullImageName}`);
    if (!pushResult.success) {
      throw new Error(`Docker push failed: ${pushResult.error}`);
    }

    logSuccess(`Image pushed: ${fullImageName}`);
  }

  // Deploy to remote host
  if (CONFIG.deployHost && CONFIG.deployHost !== 'deploy.example.com') {
    const sshCmd = `ssh -o StrictHostKeyChecking=no -p ${CONFIG.deployPort} ${CONFIG.deployUser}@${CONFIG.deployHost}`;

    // Pull and restart on remote
    const deployCommands = [
      registry ? `docker pull ${registry}/${imageName}` : '',
      `cd ${CONFIG.deployPath}`,
      'docker-compose down --remove-orphans',
      `DOCKER_IMAGE=${registry ? `${registry}/` : ''}${imageName} docker-compose up -d`,
      'docker system prune -f --filter "until=72h"',
    ].filter(Boolean).join(' && ');

    const deployResult = exec(`${sshCmd} '${deployCommands}'`);
    if (!deployResult.success) {
      throw new Error(`Remote Docker deployment failed: ${deployResult.error}`);
    }
  } else if (fileExists('docker-compose.yml') || fileExists('docker-compose.production.yml')) {
    // Local Docker Compose deployment
    const composeFile = fileExists('docker-compose.production.yml')
      ? 'docker-compose.production.yml'
      : 'docker-compose.yml';

    const result = exec(`docker-compose -f ${composeFile} up -d --build --remove-orphans`);
    if (!result.success) {
      throw new Error(`Docker Compose deployment failed: ${result.error}`);
    }
  }

  logSuccess('Docker deployment completed');
}

function deployPM2() {
  logInfo('Deploying with PM2...');

  const configFile = fileExists('ecosystem.config.js') ? 'ecosystem.config.js' : 'pm2.config.js';

  if (CONFIG.deployHost && CONFIG.deployHost !== 'deploy.example.com') {
    // Remote PM2 deployment
    const result = exec(`npx pm2 deploy ${configFile} ${CONFIG.deployTarget}`);
    if (!result.success) {
      throw new Error(`PM2 deployment failed: ${result.error}`);
    }
  } else {
    // Local PM2 deployment
    const result = exec(`npx pm2 reload ${configFile} --env production`);
    if (!result.success) {
      // Try starting fresh
      const startResult = exec(`npx pm2 start ${configFile} --env production`);
      if (!startResult.success) {
        throw new Error(`PM2 start failed: ${startResult.error}`);
      }
    }
    exec('npx pm2 save');
  }

  logSuccess('PM2 deployment completed');
}

function deploySCP() {
  logInfo('Deploying via SCP/SSH...');

  if (!CONFIG.artifactFile) {
    throw new Error('No artifact file found for deployment');
  }

  if (!CONFIG.deployHost || CONFIG.deployHost === 'deploy.example.com') {
    throw new Error('DEPLOY_HOST not configured');
  }

  const sshOpts = `-o StrictHostKeyChecking=no -p ${CONFIG.deployPort}`;
  const sshTarget = `${CONFIG.deployUser}@${CONFIG.deployHost}`;
  const remoteDir = CONFIG.deployPath;
  const releaseDir = `${remoteDir}/releases/${CONFIG.artifactName}`;
  const currentLink = `${remoteDir}/current`;

  // Create release directory
  let result = exec(`ssh ${sshOpts} ${sshTarget} "mkdir -p ${releaseDir}"`);
  if (!result.success) throw new Error(`Failed to create remote directory: ${result.error}`);

  // Upload artifact
  result = execWithRetry(`scp ${sshOpts} ${CONFIG.artifactFile} ${sshTarget}:${releaseDir}/`);
  if (!result.success) throw new Error(`Failed to upload artifact: ${result.error}`);

  // Extract and set up on remote
  const remoteCommands = [
    `cd ${releaseDir}`,
    `tar -xzf *.tar.gz`,
    `rm -f *.tar.gz`,
    // Install production dependencies only
    `npm ci --production --prefer-offline 2>/dev/null || npm install --production 2>/dev/null || true`,
    // Store previous version for rollback
    `readlink -f ${currentLink} > ${remoteDir}/.previous_release 2>/dev/null || true`,
    // Atomic symlink switch
    `ln -sfn ${releaseDir} ${currentLink}`,
    // Restart application
    `cd ${currentLink}`,
    `if command -v pm2 &> /dev/null; then pm2 reload all --update-env 2>/dev/null || pm2 start npm --name app -- start; fi`,
    // Keep only last 5 releases
    `cd ${remoteDir}/releases && ls -dt */ | tail -n +6 | xargs rm -rf 2>/dev/null || true`,
  ].join(' && ');

  result = exec(`ssh ${sshOpts} ${sshTarget} '${remoteCommands}'`, { timeout: 300000 });
  if (!result.success) throw new Error(`Remote setup failed: ${result.error}`);

  logSuccess('SCP deployment completed');
}

async function healthCheck() {
  const healthUrl = CONFIG.healthCheckUrl;

  if (!healthUrl) {
    // Try to infer health check URL
    if (CONFIG.deployHost && CONFIG.deployHost !== 'deploy.example.com') {
      logWarning('No HEALTH_CHECK_URL configured, skipping health check');
      return;
    }
    logWarning('No health check URL configured, skipping');
    return;
  }

  logInfo(`Running health check against: ${healthUrl}`);

  const maxAttempts = 10;
  const interval = Math.floor(CONFIG.healthCheckTimeout / maxAttempts);

  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    logInfo(`Health check attempt ${attempt}/${maxAttempts}...`);

    const result = exec(
      `curl -sf -o /dev/null -w "%{http_code}" --connect-timeout 5 --max-time 10 ${healthUrl}`,
      { timeout: 15000 }
    );

    if (result.success && result.output === '200') {
      logSuccess('Health check passed');
      return;
    }

    if (attempt < maxAttempts) {
      logInfo(`Waiting ${interval / 1000}s before next attempt...`);
      await new Promise(resolve => setTimeout(resolve, interval));
    }
  }

  throw new Error(`Health check failed after ${maxAttempts} attempts against ${healthUrl}`);
}

function rollback() {
  logWarning('Initiating rollback...');

  if (CONFIG.dryRun || CONFIG.skipDeploy) {
    logWarning('Rollback skipped (dry run or deployment was skipped)');
    return;
  }

  if (!CONFIG.deployHost || CONFIG.deployHost === 'deploy.example.com') {
    logWarning('Cannot rollback: no remote host configured');
    return;
  }

  const sshOpts = `-o StrictHostKeyChecking=no -p ${CONFIG.deployPort}`;
  const sshTarget = `${CONFIG.deployUser}@${CONFIG.deployHost}`;
  const remoteDir = CONFIG.deployPath;

  const rollbackCommands = [
    `if [ -f ${remoteDir}/.previous_release ]; then`,
    `  PREV=$(cat ${remoteDir}/.previous_release)`,
    `  if [ -d "$PREV" ]; then`,
    `    ln -sfn "$PREV" ${remoteDir}/current`,
    `    cd ${remoteDir}/current`,
    `    if command -v pm2 &> /dev/null; then pm2 reload all --update-env; fi`,
    `    echo "Rolled back to $PREV"`,
    `  else`,
    `    echo "Previous release directory not found"`,
    `    exit 1`,
    `  fi`,
    `else`,
    `  echo "No previous release record found"`,
    `  exit 1`,
    `fi`,
  ].join(' ');

  const result = exec(`ssh ${sshOpts} ${sshTarget} '${rollbackCommands}'`);

  if (result.success) {
    logSuccess('Rollback completed successfully');
  } else {
    logError(`Rollback failed: ${result.error}`);
  }
}

async function sendNotification(status) {
  const duration = getElapsedTime(pipelineState.startTime);

  const message = {
    status,
    version: pipelineState.version,
    commit: pipelineState.commitHash,
    branch: pipelineState.branch,
    target: CONFIG.deployTarget,
    duration,
    errors: pipelineState.errors,
    warnings: pipelineState.warnings,
    steps: pipelineState.steps.map(s => ({
      name: s.name,
      status: s.status,
      duration: s.duration,
    })),
  };

  // Slack notification
  if (CONFIG.notifySlack) {
    const emoji = status === 'success' ? '✅' : '❌';
    const color = status === 'success' ? '#36a64f' : '#dc3545';

    const slackPayload = {
      attachments: [{
        color,
        title: `${emoji} Deployment ${status.toUpperCase()}: v${message.version}`,
        fields: [
          { title: 'Branch', value: message.branch, short: true },
          { title: 'Commit', value: message.commit, short: true },
          { title: 'Target', value: message.target, short: true },
          { title: 'Duration', value: message.duration, short: true },
        ],
        footer: 'CI/CD Pipeline',
        ts: Math.floor(Date.now() / 1000),
      }],
    };

    if (message.errors.length > 0) {
      slackPayload.attachments[0].fields.push({
        title: 'Errors',
        value: message.errors.map(e => `${e.step}: ${e.error}`).join('\n'),
        short: false,
      });
    }

    const curlCmd = `curl -s -X POST -H 'Content-type: application/json' --data '${JSON.stringify(slackPayload)}' ${CONFIG.notifySlack}`;
    exec(curlCmd, { timeout: 10000 });
  }

  // Log final summary
  log('\n' + '═'.repeat(60), 'magenta');
  log('  PIPELINE SUMMARY', 'magenta');
  log('═'.repeat(60), 'magenta');
  log(`  Status:   ${status === 'success' ? '✅ SUCCESS' : '❌ FAILED'}`, status === 'success' ? 'green' : 'red');
  log(`  Version:  ${message.version}`, 'blue');
  log(`  Commit:   ${message.commit}`, 'blue');
  log(`  Branch:   ${message.branch}`, 'blue');
  log(`  Target:   ${message.target}`, 'blue');
  log(`  Duration: ${message.duration}`, 'blue');
  log('', 'reset');
  log('  Steps:', 'blue');
  pipelineState.steps.forEach(step => {
    const icon = step.status === 'success' ? '✅' : step.status === 'failed' ? '❌' : '⏳';
    log(`    ${icon} ${step.name} (${step.duration || 'N/A'})`, step.status === 'failed' ? 'red' : 'green');
  });

  if (pipelineState.warnings.length > 0) {
    log('\n  Warnings:', 'yellow');
    pipelineState.warnings.forEach(w => log(`    ⚠️  ${w}`, 'yellow'));
  }

  if (pipelineState.errors.length > 0) {
    log('\n  Errors:', 'red');
    pipelineState.errors.forEach(e => log(`    ❌ [${e.step}] ${e.error}`, 'red'));
  }

  log('\n' + '═'.repeat(60), 'magenta');
}

// ============================================================
// Main Pipeline Execution
// ============================================================

async function main() {
  log('\n🚀 CI/CD Pipeline Started', 'cyan');
  log(`   Time: ${new Date().toISOString()}`, 'cyan');
  log('', 'reset');

  let success = true;

  // Pre-flight
  success = await runStep('Gather Information', gatherInfo) && success;
  success = await runStep('Validate Environment', validateEnvironment) && success;

  if (!success) {
    await sendNotification('failed');
    process.exit(1);
  }

  // Clean
  success = await runStep('Clean Previous Build', cleanPreviousBuild) && success;

  // Install
  success = await runStep('Install Dependencies', installDependencies) && success;
  if (!success) {
    await sendNotification('failed');
    process.exit(1);
  }

  // Quality checks (run in parallel-ish fashion for speed)
  const qualityResults = await Promise.all([
    runStep('Security Audit', securityAudit),
    runStep('Linting & Type Check', runLinting),
  ]);

  // Linting failure is blocking, audit is not
  if (!qualityResults[1]) {
    success = false;
    await sendNotification('failed');
    process.exit(1);
  }

  // Test
  success = await runStep('Run Tests', runTests) && success;
  if (!success) {
    await sendNotification('failed');
    process.exit(1);
  }

  // Build
  success = await runStep('Build Application', buildApplication) && success;
  if (!success) {
    await sendNotification('failed');
    process.exit(1);
  }

  // Create artifacts
  success = await runStep('Create Artifacts', createArtifacts) && success;

  // Deploy
  const deploySuccess = await runStep('Deploy', deploy);
  if (!deploySuccess) {
    success = false;
    if (CONFIG.rollbackOnFailure) {
      await runStep('Rollback', rollback);
    }
    await sendNotification('failed');
    process.exit(1);
  }

  // Health check
  const healthSuccess = await runStep('Health Check', healthCheck);
  if (!healthSuccess) {
    success = false;
    if (CONFIG.rollbackOnFailure) {
      await runStep('Rollback', rollback);
    }
    await sendNotification('failed');
    process.exit(1);
  }

  // Final notification
  await sendNotification(success ? 'success' : 'failed');

  process.exit(success ? 0 : 1);
}

// Handle uncaught errors
process.on('uncaughtException', async (error) => {
  logError(`Uncaught exception: ${error.message}`);
  pipelineState.errors.push({ step: 'uncaught', error: error.message });
  await sendNotification('failed');
  process.exit(1);
});

process.on('unhandledRejection', async (reason) => {
  logError(`Unhandled rejection: ${reason}`);
  pipelineState.errors.push({ step: 'unhandled', error: String(reason) });
  await sendNotification('failed');
  process.exit(1);
});

// Handle SIGINT/SIGTERM for graceful shutdown
['SIGINT', 'SIGTERM'].forEach(signal => {
  process.on(signal, async () => {
    logWarning(`Received ${signal}, aborting pipeline...`);
    pipelineState.errors.push({ step: 'signal', error: `Pipeline aborted by ${signal}` });
    await sendNotification('failed');
    process.exit(130);
  });
});

// Run
main();